CREATE PROVIDER open_ai_provider
ENGINE = OpenAI(
	api_key='sk-proj-xxx',
	model_name = 'gpt-3.5-turbo'
);

CREATE MODEL query_model(
    input
) USING open_ai_provider(model_name = 'gpt-4o')
PROMPT query_prompt
TOOLS (
    get_semantics COMMENT 'Tool to get the schemas of the tables in the database',
    langdb_raw_query COMMENT 'Tool to execute SQL query over the database',
    query_validator COMMENT 'Model to Validate the generated SQL query'
)
SETTINGS retries = 3;

CREATE PROVIDER open_ai_provider
ENGINE = OpenAI(
	api_key='sk-proj-xxx',
	model_name = 'gpt-4o-mini'
);

CREATE MODEL example_model(
    input
) USING open_ai_provider()
PROMPT ( system "You are an helpful assistant. Help the user with his queries",
human "{{input}}"
);

CREATE EMBEDDING MODEL IF NOT EXISTS example_embed(
input COMMENT 'This is the input of the content whose embeddings are created'
) USING open_ai_provider(embedding_model='text-embedding-ada-002', encoding_format='float', dimensions=100)

CREATE TABLE products (
    product_id UInt32,
    product_name String
) ENGINE = MergeTree
ORDER BY product_id;

CREATE PROMPT customer_review_pt (
  system "You are an AI assistant. Look at the provided review and return average sentiment score for the review.
    Strictly only return a number between 1 and 5 as a value without any description.
    ",
  human "{{review}}"
);

CREATE PROVIDER open_ai_provider
ENGINE = OpenAI(
	api_key='sk-proj-xxx',
	model_name = 'gpt-4o-mini'
);

CREATE MODEL review(
    review
) USING open_ai_provider()
PROMPT customer_review_pt;

CREATE TABLE [IF NOT EXISTS] table_name
(
    col_name1 [type1],
    col_name2 [type2],
    ...
) ENGINE = MongoDB(host:port, database, collection, user, password );

