CREATE TABLE cities_links (
	`city` String,
	`link` String
) engine = MergeTree
order by city;

INSERT INTO cities_pdf(content, metadata, city) 
SELECT content, metadata, JSONExtractString(metadata,'city')
FROM load_pdf_text((SELECT link, city from cities_links));

